const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const lead_id = body.lead_id || null;
if (!lead_id) return { json: { _error: true, error: 'lead_id required', ok: false } };
return { json: { lead_id } };

const arr = $input.item.json || [];
const row = Array.isArray(arr) && arr.length > 0 ? arr[0] : null;
if (!row) return { json: { _skip: true, reason: 'lead not found', ok: false } };
if (row.do_not_contact) return { json: { _skip: true, reason: 'do_not_contact', ok: false, lead_id: row.id, category: 'skip', score: 0 } };

// Build prompt
const system_prompt = 'You are Crystallux Task Classifier. Classify this lead into exactly one category: reply | hot_lead | no_show_rebook | upcoming_call | follow_up | skip. Output STRICT JSON: { category: string, score: number (0-100), reason: string (<100 chars) }.';
const user_prompt = 'Lead:\n' + JSON.stringify(row, null, 2);
return { json: { lead_id: row.id, lead: row, system_prompt, user_prompt } };

const resp = $input.item.json || {};
const prep = $('Prep Prompt').first().json;
const lead = prep.lead || {};

let parsed = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) parsed = JSON.parse(text.trim());
} catch (e) { parsed = null; }

if (!parsed || !parsed.category) {
  // Deterministic fallback
  let category = 'follow_up';
  let score = 30;
  let reason = 'Claude unavailable; fallback heuristic';
  if (lead.reply_received && !lead.reply_handled) { category = 'reply'; score = 100; reason = 'unreplied inbound'; }
  else if ((lead.lead_score || 0) >= 80) { category = 'hot_lead'; score = 85; reason = 'score >= 80'; }
  parsed = { category, score, reason };
}

return { json: { ok: true, lead_id: prep.lead_id, category: parsed.category, score: parsed.score, reason: parsed.reason } };
